const fs = require('fs');
const path = require('path');
const body = $input.first().json.body || $input.first().json;
const title = body.title || body.subject || 'Untitled';
const url = body.url || body.link || '#';
const summary = (body.summary || body.description || '').toString().slice(0, 200);
const d = new Date();
const yyyy = d.getFullYear();
const mm = String(d.getMonth() + 1).padStart(2, '0');
const dd = String(d.getDate()).padStart(2, '0');
const filePath = `/vault/inbox/rss/${yyyy}-${mm}-${dd}.md`;
const hh = String(d.getHours()).padStart(2, '0');
const mi = String(d.getMinutes()).padStart(2, '0');
const line = `- ${hh}:${mi} [${title}](${url}) — ${summary}\n`;
fs.mkdirSync(path.dirname(filePath), { recursive: true });
if (!fs.existsSync(filePath)) {
  const header = `---\ncreated: ${yyyy}-${mm}-${dd}\ntype: rss-digest\n---\n\n# ${yyyy}-${mm}-${dd} RSS\n\n`;
  fs.writeFileSync(filePath, header, 'utf8');
}
fs.appendFileSync(filePath, line, 'utf8');
return [{ json: { ok: true, written: filePath, title } }];
